plugin.detectCode:
const t = input.trim();
const hasSection = /^\[\w[\w ]*\]$/m.test(t);
const hasKV = /^\w[\w.\-]*\s*[=:]\s*.+$/m.test(t);
return (hasKV || hasSection) ? 0.85 : 0;

plugin.executeCode:
const lines = input.split('\n');
const out = [];
let prevWasContent = false;
for (const raw of lines) {
  const trimmed = raw.trim();
  if (!trimmed) {
    if (prevWasContent) out.push('');
    prevWasContent = false;
    continue;
  }
  // Comment
  if (trimmed.startsWith(';') || trimmed.startsWith('#')) {
    out.push(trimmed);
    prevWasContent = true;
    continue;
  }
  // Section header
  if (/^\[.+\]$/.test(trimmed)) {
    if (out.length > 0 && out[out.length - 1] !== '') out.push('');
    out.push(trimmed);
    prevWasContent = true;
    continue;
  }
  // Key = value or Key : value
  const m = trimmed.match(/^([^=:]+)([=:])(.*)$/);
  if (m) {
    const key = m[1].trimEnd();
    const sep = m[2];
    const val = m[3].trimStart();
    out.push(`${key} ${sep} ${val}`);
    prevWasContent = true;
    continue;
  }
  out.push(trimmed);
  prevWasContent = true;
}
while (out.length && !out[out.length - 1]) out.pop();
return { output: out.join('\n') + '\n', outputLanguage: 'ini' };
